import{_ as a,a as d,b as t,c as o,d as i,e as n,f as l,g as r}from"./chunks/无关系记录重新申请.D_1qirb1.js";import{_ as s,o as p,c,a2 as h}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"Федеративний розподілений індекс","description":"","frontmatter":{},"headers":[],"relativePath":"uk-UA/Other/federated-distributed-index.md","filePath":"uk-UA/Other/federated-distributed-index.md","lastUpdated":1781962217000}'),u={name:"uk-UA/Other/federated-distributed-index.md"};function b(f,e,m,x,g,q){return p(),c("div",null,[...e[0]||(e[0]=[h('<h1 id="федеративнии-розподілении-індекс" tabindex="-1">Федеративний розподілений індекс <a class="header-anchor" href="#федеративнии-розподілении-індекс" aria-label="Permalink to &quot;Федеративний розподілений індекс&quot;">​</a></h1><p>Федеративний розподілений індекс дозволяє кільком сайтам ImgBed обмінюватися списками файлів.</p><p>Простіше кажучи:</p><ul><li>ви можете поділитися вибраними папками зі свого сайту з іншими;</li><li>можете приєднатися до іншого вузла й синхронізувати його спільний список файлів у свою адмін-панель;</li><li>federated files призначені переважно для перегляду, пошуку й відкриття посилань. Вони не перезавантажуються у ваше власне сховище.</li></ul><h2 id="де-це-налаштовується" tabindex="-1">Де це налаштовується <a class="header-anchor" href="#де-це-налаштовується" aria-label="Permalink to &quot;Де це налаштовується&quot;">​</a></h2><p>Відкрийте:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Federated Distributed Index</span></span></code></pre></div><p><img src="'+a+`" alt="Локальний federation node" loading="lazy"></p><p>На сторінці є три вкладки:</p><table tabindex="0"><thead><tr><th>Вкладка</th><th>Призначення</th></tr></thead><tbody><tr><td>Local Node</td><td>Увімкнути свій node, підтвердити публічний домен, вибрати спільні папки й оновити outbound index</td></tr><tr><td>Nodes I Joined</td><td>Керувати іншими ImgBed nodes, до яких ви приєдналися</td></tr><tr><td>Nodes Joining Me</td><td>Керувати запитами від інших, хто хоче приєднатися до вашого node</td></tr></tbody></table><h2 id="перше-налаштування" tabindex="-1">Перше налаштування <a class="header-anchor" href="#перше-налаштування" aria-label="Permalink to &quot;Перше налаштування&quot;">​</a></h2><ol><li>Відкрийте <code>Local Node</code>.</li><li>Увімкніть <code>Enable</code>.</li><li>У <code>Sync folders</code> виберіть папки, якими хочете поділитися.</li><li>Натисніть <code>Update Outbound Index</code>.</li><li>Якщо ImgBed виявить зміну домену, підтвердьте, що поточний домен правильний.</li></ol><p>Можна вибрати кілька sync folders.</p><p>Якщо список sync folder порожній, поширюються всі папки.</p><h2 id="local-node" tabindex="-1">Local Node <a class="header-anchor" href="#local-node" aria-label="Permalink to &quot;Local Node&quot;">​</a></h2><h3 id="public-domain" tabindex="-1">Public Domain <a class="header-anchor" href="#public-domain" aria-label="Permalink to &quot;Public Domain&quot;">​</a></h3><p>Public domain — це URL сайту, через який інші nodes звертаються до вашого node.</p><p>ImgBed визначає його автоматично. Вводити вручну не потрібно. Під час першого оновлення індексу ImgBed попросить підтвердити, чи поточний URL доступу є production-доменом.</p><p>Якщо пізніше змінити домен, оновлення індексу знову попросить підтвердження.</p><h3 id="sync-folders" tabindex="-1">Sync Folders <a class="header-anchor" href="#sync-folders" aria-label="Permalink to &quot;Sync Folders&quot;">​</a></h3><p>Sync folders визначають, які файли поширюються для federation nodes.</p><p>Наприклад, якщо вибрати тільки:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/</span></span>
<span class="line"><span>/2/</span></span></code></pre></div><p>інші nodes бачитимуть лише файли в цих двох директоріях.</p><h3 id="update-outbound-index" tabindex="-1">Update Outbound Index <a class="header-anchor" href="#update-outbound-index" aria-label="Permalink to &quot;Update Outbound Index&quot;">​</a></h3><p>Оновлює список файлів, який інші nodes можуть синхронізувати з вашого сайту.</p><p>Використовуйте це, коли:</p><ul><li>ви вперше вмикаєте federation;</li><li>завантажили файли, якими хочете поділитися;</li><li>змінили sync folders;</li><li>змінили public domain і потрібно його підтвердити.</li></ul><h2 id="nodes-i-joined" tabindex="-1">Nodes I Joined <a class="header-anchor" href="#nodes-i-joined" aria-label="Permalink to &quot;Nodes I Joined&quot;">​</a></h2><p><code>Nodes I Joined</code> — місце, де ви підписуєтеся на інші nodes.</p><p><img src="`+d+'" alt="Nodes I joined" loading="lazy"></p><h3 id="запит-на-приєднання-до-іншого-node" tabindex="-1">Запит на приєднання до іншого node <a class="header-anchor" href="#запит-на-приєднання-до-іншого-node" aria-label="Permalink to &quot;Запит на приєднання до іншого node&quot;">​</a></h3><ol><li>Попросіть у власника іншого сайту invitation link.</li><li>Вставте його в поле введення.</li><li>Натисніть <code>Request to Join</code>.</li><li>Дочекайтеся, поки інший власник схвалить запит у своїй адмін-панелі.</li></ol><p>Після схвалення статус node стане approved.</p><h3 id="update-inbound-index" tabindex="-1">Update Inbound Index <a class="header-anchor" href="#update-inbound-index" aria-label="Permalink to &quot;Update Inbound Index&quot;">​</a></h3><p><code>Update Inbound Index</code> синхронізує списки файлів із nodes, до яких ви приєдналися.</p><p>Використовуйте це, коли:</p><ul><li>інший власник щойно схвалив ваш запит;</li><li>інший власник повідомив, що спільний контент оновлено;</li><li>ви хочете оновити всі підключені federation file lists.</li></ul><p>Щоб оновити тільки один node, натисніть <code>Update Index</code> на його картці.</p><p><img src="'+t+'" alt="Оновлення індексу" loading="lazy"></p><h3 id="unsubscribe" tabindex="-1">Unsubscribe <a class="header-anchor" href="#unsubscribe" aria-label="Permalink to &quot;Unsubscribe&quot;">​</a></h3><p>Якщо більше не хочете синхронізувати node, натисніть <code>Unsubscribe</code>.</p><p>Після відписки federated index цього node буде видалено з вашого локального сайту.</p><h2 id="nodes-joining-me" tabindex="-1">Nodes Joining Me <a class="header-anchor" href="#nodes-joining-me" aria-label="Permalink to &quot;Nodes Joining Me&quot;">​</a></h2><p><code>Nodes Joining Me</code> — місце для обробки запитів від інших.</p><p><img src="'+o+'" alt="Nodes joining me" loading="lazy"></p><h3 id="створення-invitation-link" tabindex="-1">Створення invitation link <a class="header-anchor" href="#створення-invitation-link" aria-label="Permalink to &quot;Створення invitation link&quot;">​</a></h3><ol><li>Переконайтеся, що local node увімкнений.</li><li>Натисніть <code>Update Outbound Index</code> принаймні один раз, щоб ImgBed підтвердив public domain.</li><li>Відкрийте <code>Nodes Joining Me</code>.</li><li>Натисніть <code>Reset Invitation Link</code>.</li><li>Скопіюйте invitation link і надішліть його іншому власнику.</li></ol><p>Якщо invitation link порожній, public domain зазвичай ще не підтверджено. Поверніться до <code>Local Node</code> і натисніть <code>Update Outbound Index</code>.</p><h3 id="обробка-запитів" tabindex="-1">Обробка запитів <a class="header-anchor" href="#обробка-запитів" aria-label="Permalink to &quot;Обробка запитів&quot;">​</a></h3><p>Коли хтось надсилає запит, він з&#39;являється в списку <code>Nodes Joining Me</code>.</p><table tabindex="0"><thead><tr><th>Дія</th><th>Значення</th></tr></thead><tbody><tr><td>Approve</td><td>Дозволяє іншому node синхронізувати ваш спільний список файлів</td></tr><tr><td>Reject</td><td>Відхиляє запит на приєднання</td></tr><tr><td>Delete</td><td>Видаляє завершений запис</td></tr><tr><td>Check Status</td><td>Перевіряє, чи інша сторона все ще підтримує цей зв&#39;язок</td></tr></tbody></table><p>Після схвалення інша сторона все одно має натиснути <code>Update Inbound Index</code>, перш ніж ваші спільні файли з&#39;являться в неї.</p><p><img src="'+i+'" alt="Схвалення запрошеного node" loading="lazy"></p><h2 id="повідомлення" tabindex="-1">Повідомлення <a class="header-anchor" href="#повідомлення" aria-label="Permalink to &quot;Повідомлення&quot;">​</a></h2><p>Після схвалення зв&#39;язку натисніть <code>Message</code> на картці node.</p><p>Повідомлення призначені лише для спілкування щодо federation relationship. Вони не змінюють файли, теги, директорії або permissions.</p><p><img src="'+n+'" alt="Повідомлення" loading="lazy"></p><h2 id="перегляд-federated-files" tabindex="-1">Перегляд federated files <a class="header-anchor" href="#перегляд-federated-files" aria-label="Permalink to &quot;Перегляд federated files&quot;">​</a></h2><p>Після завершення синхронізації поверніться до списку файлів в адмін-панелі.</p><p>Угорі сторінки можна перемикатися між локальними файлами й federated files. У federated files можна переглядати синхронізований контент.</p><p>Federated files призначені переважно для перегляду, пошуку, preview і копіювання посилань. Це не локальні файли, тому їх не можна переміщувати, видаляти, пере тегувати або резервно копіювати зі свого сайту.</p><p><img src="'+l+'" alt="Federated files в адмін-панелі" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="чому-система-просить-подати-заявку-знову-бо-relationship-record-відсутніи" tabindex="-1">Чому система просить подати заявку знову, бо relationship record відсутній? <a class="header-anchor" href="#чому-система-просить-подати-заявку-знову-бо-relationship-record-відсутніи" aria-label="Permalink to &quot;Чому система просить подати заявку знову, бо relationship record відсутній?&quot;">​</a></h3><p>Зазвичай це означає, що інша сторона видалила вас і прибрала запис, тому зв&#39;язок більше не знаходиться. Надішліть новий join request.</p><p><img src="'+r+'" alt="Повторна заявка, коли relationship record відсутній" loading="lazy"></p><h3 id="чому-після-приєднання-я-не-бачу-фаилів" tabindex="-1">Чому після приєднання я не бачу файлів? <a class="header-anchor" href="#чому-після-приєднання-я-не-бачу-фаилів" aria-label="Permalink to &quot;Чому після приєднання я не бачу файлів?&quot;">​</a></h3><p>Перевірте:</p><ol><li>Інший власник схвалив ваш запит.</li><li>Інший власник натиснув <code>Update Outbound Index</code>.</li><li>Ви натиснули <code>Update Inbound Index</code>.</li><li>Sync folders іншого власника містять директорії, якими він хоче поділитися.</li></ol><h3 id="що-робити-коли-виявлено-зміну-домену" tabindex="-1">Що робити, коли виявлено зміну домену? <a class="header-anchor" href="#що-робити-коли-виявлено-зміну-домену" aria-label="Permalink to &quot;Що робити, коли виявлено зміну домену?&quot;">​</a></h3><p>Якщо ви зараз відкрили адмін-панель через production-домен, підтвердьте й продовжуйте.</p><p>Якщо використовується тимчасова адреса, скасуйте, відкрийте адмін-панель через production-домен і спробуйте ще раз.</p><h3 id="що-означає-порожніи-список-sync-folder" tabindex="-1">Що означає порожній список Sync Folder? <a class="header-anchor" href="#що-означає-порожніи-список-sync-folder" aria-label="Permalink to &quot;Що означає порожній список Sync Folder?&quot;">​</a></h3><p>Порожній список sync folder означає, що поширюються всі папки.</p><p>Щоб поширювати тільки окремі директорії, виберіть їх вручну.</p><h3 id="різниця-між-outbound-і-inbound-index-updates" tabindex="-1">Різниця між Outbound і Inbound Index Updates <a class="header-anchor" href="#різниця-між-outbound-і-inbound-index-updates" aria-label="Permalink to &quot;Різниця між Outbound і Inbound Index Updates&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Кнопка</th><th>Просте значення</th></tr></thead><tbody><tr><td>Update Outbound Index</td><td>Оновлює те, що інші можуть синхронізувати від мене</td></tr><tr><td>Update Inbound Index</td><td>Оновлює те, що я синхронізував від інших</td></tr></tbody></table>',78)])])}const y=s(u,[["render",b]]);export{_ as __pageData,y as default};
